class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int longest = 0;
        int zeroCount = 0;
        int oneCount = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '0') {
                zeroCount++;
            } else {
                oneCount++;
            }
            if (zeroCount == oneCount) {
                longest = Math.max(longest, i + 1);
            }
        }
        return longest;
    }
}
